+const MAX_FAILED_LOGIN_ATTEMPTS = 5;
+const failedLoginAttempts = new Map<string, number>();
+
+export function validateEmail(email: string): boolean {
+  return /^[^@]+@[^@]+$/.test(email);
+}
+
+export function login(email: string, password: string): boolean {
+  if (!validateEmail(email)) return false;
+  if (shouldRateLimit(email)) return false;
+  if (password.length < 8) {
+    recordFailedAttempt(email);
+    return false;
+  }
+  failedLoginAttempts.delete(email);
+  return true;
+}
+
+function shouldRateLimit(email: string): boolean {
+  return (failedLoginAttempts.get(email) ?? 0) >= MAX_FAILED_LOGIN_ATTEMPTS;
+}
+
+function recordFailedAttempt(email: string): void {
+  failedLoginAttempts.set(email, (failedLoginAttempts.get(email) ?? 0) + 1);
+}

